@@ -23,8 +23,11 @@ public class TimeTunnelView extends ResultView<TimeTunnelModel> {

     @Override
     public void draw(CommandProcess process, TimeTunnelModel timeTunnelModel) {
+        int sizeLimitValue = GlobalOptions.objectSizeLimit;
         Integer sizeLimit = timeTunnelModel.getSizeLimit();
-        int sizeLimitValue = sizeLimit != null ? sizeLimit : GlobalOptions.objectSizeLimit;
+        if (sizeLimit != null) {
+            sizeLimitValue = sizeLimit.intValue();
+        }

         if (timeTunnelModel.getTimeFragmentList() != null) {
             //show list table: tt -l / tt -t
diff --git a/core/src/main/java/com/taobao/arthas/core/command/view/WatchView.java b/core/src/main/java/com/taobao/arthas/core/command/view/WatchView.java
index 10e4e324..398153cf 100644
--- a/core/src/main/java/com/taobao/arthas/core/command/view/WatchView.java
+++ b/core/src/main/java/com/taobao/arthas/core/command/view/WatchView.java
@@ -18,7 +18,11 @@ public class WatchView extends ResultView<WatchModel> {
     @Override
     public void draw(CommandProcess process, WatchModel model) {
         ObjectVO objectVO = model.getValue();
-        int sizeLimit = model.getSizeLimit() != null ? model.getSizeLimit() : GlobalOptions.objectSizeLimit;
+        int sizeLimit = GlobalOptions.objectSizeLimit;
+        Integer modelSizeLimit = model.getSizeLimit();
+        if (modelSizeLimit != null) {
+            sizeLimit = modelSizeLimit.intValue();
+        }
         String result = StringUtils.objectToString(
                 objectVO.needExpand() ? new ObjectView(sizeLimit, objectVO).draw() : objectVO.getObject());

diff --git a/core/src/main/java/com/taobao/arthas/core/view/ObjectView.java b/core/src/main/java/com/taobao/arthas/core/view/ObjectView.java
index 7e133235..f8d2f871 100644
--- a/core/src/main/java/com/taobao/arthas/core/view/ObjectView.java
+++ b/core/src/main/java/com/taobao/arthas/core/view/ObjectView.java
@@ -700,7 +700,10 @@ public class ObjectView implements View {

     private static int defaultMaxObjectLength() {
         int limit = GlobalOptions.objectSizeLimit;
-        return limit > 0 ? limit : ArthasConstants.MAX_HTTP_CONTENT_LENGTH;
+        if (limit > 0) {
+            return limit;
+        }
+        return ArthasConstants.MAX_HTTP_CONTENT_LENGTH;
     }

 }

